questions.solutionCode:
function countDifferentBits(hex1, hex2) {
  let count = 0;
  for (let i = 0; i < hex1.length; i++) {
    let xor = parseInt(hex1[i], 16) ^ parseInt(hex2[i], 16);
    while (xor > 0) {
      count += xor & 1;
      xor >>= 1;
    }
  }
  return count;
}
